:root {
  --bg: #05070a;
  --bg-panel: #0b0f1a;
  --card: rgba(15, 23, 42, 0.6);
  --panel-border: rgba(255, 255, 255, 0.08);
  --primary: #00d2ff;
  --neon-blue: #00d2ff;
  --neon-green: #39ff14;
  --neon-red: #ff3131;
  --neon-yellow: #ffea00;
  --neon-violet: #a855f7;
  --text-main: #f8fafc;
  --text-muted: #64748b;
  --glass: rgba(10, 15, 25, 0.7);
}

body {
  margin: 0;
  padding: 0;
  background-color: var(--bg);
  background-image: radial-gradient(circle at 50% 50%, #1e293b 0%, #05070a 100%);
  color: var(--text-main);
  font-family: 'Inter', sans-serif;
  overflow: hidden;
  -webkit-text-size-adjust: 100%;
  -webkit-tap-highlight-color: transparent;
}

* {
  box-sizing: border-box;
  max-width: 100%;
}

.app-container {
  display: flex;
  height: 100vh;
  height: 100dvh;
  width: 100vw;
  overflow: hidden;
}

@media (max-width: 768px) {
  .app-container {
    flex-direction: column;
    height: 100dvh;
    overflow: hidden;
  }
}

/* Sidebar Styling */
.sidebar {
  width: 240px;
  min-width: 240px;
  background: #111827;
  border-right: 1px solid var(--panel-border);
  display: flex;
  flex-direction: column;
  padding: 1rem;
  overflow-y: auto;
  overflow-x: hidden;
}

@media (max-width: 768px) {
  .sidebar {
    width: 100%;
    min-width: 100%;
    height: auto;
    max-height: 45vh;
    border-right: none;
    border-bottom: 1px solid var(--panel-border);
    padding: 0.75rem;
    flex-direction: row;
    flex-wrap: wrap;
    gap: 0;
    align-items: flex-start;
  }
  .sidebar > div:first-child {
    width: 100%;
    margin-bottom: 0.5rem;
  }
  .sidebar > div:first-child h1 {
    font-size: 1.1rem !important;
  }
  .sidebar nav {
    flex-direction: row !important;
    flex-wrap: wrap;
    gap: 4px !important;
    width: 100%;
  }
  .sidebar nav button {
    padding: 6px 10px !important;
    font-size: 0.7rem !important;
    flex: 1;
    min-width: calc(50% - 4px);
    justify-content: center;
  }
  .sidebar > div:last-child {
    width: 100%;
    padding: 0.5rem !important;
    margin-top: 0.5rem !important;
    display: flex;
    align-items: center;
    justify-content: space-between;
  }
  .sidebar > div:last-child > div {
    margin-bottom: 0 !important;
  }
  .sidebar > div:last-child button {
    width: auto !important;
    padding: 6px 12px !important;
  }
}

.stat-widget {
  background: var(--card);
  border-radius: 1rem;
  padding: 1.25rem;
  margin-bottom: 1rem;
  border: 1px solid var(--panel-border);
}

.stat-value {
  font-size: 2rem;
  font-weight: 800;
  line-height: 1;
}

.stat-label {
  color: var(--text-muted);
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 1px;
}

/* Factory Map Styling */
.main-content {
  flex: 1;
  padding: 1rem;
  background: #0b0f1a;
  overflow: auto;
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
}

@media (max-width: 768px) {
  .main-content {
    padding: 0.5rem;
    flex: 1;
    overflow-y: auto;
    overflow-x: hidden;
    height: 55vh;
  }
}

.factory-map-container {
  flex: 1;
  overflow: auto;
  border-radius: 16px;
  padding: 8px;
}

@media (max-width: 768px) {
  .factory-map-container {
    border-radius: 12px;
    padding: 4px;
    overflow-x: auto;
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
  }
}

.factory-bg {
  position: relative;
  width: 1200px;
  height: 800px;
  background: #111827;
  border-radius: 8px;
  border: 3px solid #334155;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  background-image: 
    linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px);
  background-size: 25px 25px;
}

@media (max-width: 768px) {
  .factory-bg {
    width: 800px;
    height: 600px;
    transform-origin: top left;
  }
}

.zone-label {
  position: absolute;
  color: var(--text-muted);
  font-weight: 700;
  font-size: 0.9rem;
  pointer-events: none;
  text-transform: uppercase;
  letter-spacing: 3px;
  opacity: 0.5;
}

.machine-node {
  position: absolute;
  width: 48px;
  height: 48px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(4px);
  touch-action: manipulation;
}

@media (max-width: 768px) {
  .machine-node {
    width: 40px;
    height: 40px;
    border-radius: 10px;
  }
  .machine-node:hover {
    transform: scale(1.1) translateY(-2px);
  }
}

.machine-node:hover {
  transform: scale(1.2) translateY(-5px);
  z-index: 10;
  box-shadow: 0 0 20px rgba(0, 210, 255, 0.5);
}

.machine-node.is-focused {
  border-color: var(--primary);
  box-shadow: 0 0 30px rgba(0, 210, 255, 0.6);
  z-index: 5;
}

.smart-pulse {
  position: absolute;
  width: 100%;
  height: 100%;
  border: 2px solid var(--primary);
  border-radius: 50%;
  animation: smart-ripple 1.5s infinite;
  pointer-events: none;
}

@keyframes smart-ripple {
  0% { transform: scale(0.5); opacity: 1; }
  100% { transform: scale(2.5); opacity: 0; }
}

.machine-node.running {
  background: rgba(57, 255, 20, 0.1);
  color: var(--neon-green);
  border-color: var(--neon-green);
  box-shadow: 0 0 10px rgba(57, 255, 20, 0.2);
  animation: neon-pulse-green 2s infinite;
}

.machine-node.stopped {
  background: rgba(255, 49, 49, 0.1);
  color: var(--neon-red);
  border-color: var(--neon-red);
}

.machine-node.warning {
  background: rgba(255, 234, 0, 0.1);
  color: var(--neon-yellow);
  border-color: var(--neon-yellow);
  animation: neon-pulse-yellow 2s infinite;
}

.machine-node.searching {
  background: rgba(168, 85, 247, 0.2);
  color: #c084fc;
  border-color: #a855f7;
  box-shadow: 0 0 15px rgba(168, 85, 247, 0.4);
  animation: neon-pulse-violet 2s infinite;
}

.searching .icon {
  animation: searching-rotate 2s linear infinite;
}

@keyframes searching-rotate {
  0% { transform: scale(1); opacity: 0.7; }
  50% { transform: scale(1.1); opacity: 1; }
  100% { transform: scale(1); opacity: 0.7; }
}

@keyframes neon-pulse-green {
  0% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
  50% { box-shadow: 0 0 25px rgba(57, 255, 20, 0.7), 0 0 40px rgba(57, 255, 20, 0.3); }
  100% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
}

@keyframes neon-pulse-violet {
  0% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
  50% { box-shadow: 0 0 25px rgba(168, 85, 247, 0.7), 0 0 40px rgba(168, 85, 247, 0.3); }
  100% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
}

/* Tab Switcher */
.tab-switcher {
  display: flex;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  padding: 3px;
  gap: 3px;
}

.tab-switcher button {
  background: transparent;
  border: none;
  color: var(--text-muted);
  font-size: 0.65rem;
  font-weight: 800;
  padding: 5px 12px;
  border-radius: 6px;
  cursor: pointer;
  transition: 0.2s;
